import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine().trim(); // Read the entire line including spaces and trim leading/trailing whitespaces

        // Limit the size of the input to prevent buffer overflow
        int bufferSize = 10;
        char[] buffer = new char[bufferSize];

        // Copy only up to bufferSize characters from user input into the buffer
        for (int i = 0; i < Math.min(input.length(), bufferSize); i++) {
            buffer[i] = input.charAt(i);
        }

        System.out.println("Input stored in buffer: " + String.valueOf(buffer));
    }
}

